const { symptoms, age, sex, existingConditions, medications } = $input.first().json.body.data;

const patientContext = `Patient: ${age ? `age ${age}` : 'age not specified'}, ${sex || 'sex not specified'}. ${existingConditions ? `Existing conditions: ${existingConditions}.` : ''} ${medications ? `Current medications: ${medications}.` : ''}`;

const symptomMatchQuery = `Medical conditions and differential diagnoses commonly associated with these symptoms: ${symptoms}. ${patientContext} Include prevalence data and red flags. Do NOT provide a diagnosis, only list possible conditions for physician consideration.`;

const testRecommendQuery = `Recommended medical tests, examinations, and laboratory workup for evaluating these symptoms: ${symptoms}. ${patientContext} Include: test name, what it measures, why it's relevant, typical cost range, and urgency level.`;

const specialistQuery = `Which medical specialists should evaluate a patient with these symptoms: ${symptoms}. ${patientContext}`;

return {
  json: {
    symptoms, age, sex, existingConditions, medications,
    patientContext,
    queries: { symptomMatch: symptomMatchQuery, testRecommend: testRecommendQuery, specialist: specialistQuery }
  }
};

const items = $input.all();
const parts = [];

for (const item of items) {
  // Perplexity results
  const content = item.json?.choices?.[0]?.message?.content;
  if (content) parts.push(content);
  // Anthropic results (Specialist Advisor)
  const anthropicContent = item.json?.content?.[0]?.text;
  if (anthropicContent) parts.push(anthropicContent);
}

const firstItem = $input.first().json;
const symptoms = firstItem.symptoms || firstItem.body?.data?.symptoms || 'N/A';
const age = firstItem.age || firstItem.body?.data?.age || '';
const sex = firstItem.sex || firstItem.body?.data?.sex || '';

const userMessage = `სიმპტომები: ${symptoms}\nასაკი: ${age}\nსქესი: ${sex}\n\nინტერნეტ ძიების შედეგები:\n${parts.join('\n\n---\n\n')}`;

return { json: { userMessage } };

const raw = $input.first().json;
const text = raw.content?.[0]?.text || '';

let parsed = null;

// Try code fence
const fenceMatch = text.match(/```(?:json)?\s*(\{[\s\S]*?\})\s*```/);
if (fenceMatch) {
  try { parsed = JSON.parse(fenceMatch[1]); } catch(e) {}
}

// Try full text
if (!parsed) {
  try { parsed = JSON.parse(text.trim()); } catch(e) {}
}

if (parsed && (parsed.meta || parsed.items || parsed.sections)) {
  return { json: parsed };
}

// Fallback: return text as summary
return { json: { meta: 'სიმპტომების ანალიზი', items: [], summary: text } };
